import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileReader;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVParserParseFileTest {

    File mockFile;
    CSVFormat mockFormat;

    @BeforeEach
    void setup() {
        mockFile = mock(File.class);
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void parse_nullFile_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse((File) null, mockFormat));
        assertEquals("file", ex.getMessage());
    }

    @Test
    void parse_nullFormat_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(mockFile, null));
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_validFileAndFormat_returnsCSVParser() throws IOException {
        try (MockedConstruction<FileReader> mockedFileReader = Mockito.mockConstruction(FileReader.class)) {
            CSVParser parser = CSVParser.parse(mockFile, mockFormat);
            assertNotNull(parser);
            // The returned object is a CSVParser instance
            assertTrue(parser instanceof CSVParser);
        }
    }
}
